  ('heelevel3-1fb53453-moex-00179', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-112-3082b5f1', 'sub-heelevel3-1fb53453-02', NULL, 'single_choice', '財政部以營利事業欠稅為由，函請內政部移民署限制營利事業負責人出境，並通知營利事業負責 人。下列敘述何者錯誤？', '["限制出境之決定乃係行政處分", "限制出境之決定係內政部移民署所作成的行政處分", "內政部移民署所為限制出境之決定屬多階段行政處分", "營利事業負責人不得以不服財政部通知為由向行政院提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "330", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
